$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/donation_report_ajax';

    var table = $('#view_donation').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,

        columnDefs: [{
            defaultContent: "-",
            targets: 0,
            render: function (data, type, row, meta) {
                return meta.row + 1;
            }
        }],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.from_date = $('.from_date').val();
                d.to_date = $('.to_date').val();
                d.financial_year = $('.financial_year').val();
                d.category = $('.category').val();
            }
        },

        columns: [
            { data: null },
            { data: "category_name" },
            { data: "subcategory_name" },
            { data: "customer_name" },
            { data: "date" },
            { data: "Akki" },
            { data: "Kai" },
            { data: "Oil" },

            {
                title: 'Action',
                render: function (data, type, full) {
                    return `<a href='edit_donation/${full.id}'><i class="ti-pencil-alt"></i></a>`;
                }
            }
        ]
    });

    // Filter button
    $('.submit_purchase_report').click(function () {
        table.ajax.reload();   // Reload data only
    });

});